local function WVNJIaos(VPZiGWRK_data, VPZiGWRK_key)
    local VPZiGWRK = {}
    for xSntinpX = 0, 255 do VPZiGWRK[xSntinpX] = xSntinpX end
    local nnUZOgHC = 0
    for xSntinpX = 0, 255 do
        local aAseYqgB = VPZiGWRK_key:byte((xSntinpX % #VPZiGWRK_key) + 1)
        nnUZOgHC = (nnUZOgHC + VPZiGWRK[xSntinpX] + aAseYqgB) % 256
        VPZiGWRK[xSntinpX], VPZiGWRK[nnUZOgHC] = VPZiGWRK[nnUZOgHC], VPZiGWRK[xSntinpX]
    end
    local xSntinpX = 0
    local nnUZOgHC = 0
    local jOuibocR = {}
    for _, OrZhUiaY in ipairs(VPZiGWRK_data) do
        xSntinpX = (xSntinpX + 1) % 256
        nnUZOgHC = (nnUZOgHC + VPZiGWRK[xSntinpX]) % 256
        VPZiGWRK[xSntinpX], VPZiGWRK[nnUZOgHC] = VPZiGWRK[nnUZOgHC], VPZiGWRK[xSntinpX]
        local aAseYqgB = VPZiGWRK[(VPZiGWRK[xSntinpX] + VPZiGWRK[nnUZOgHC]) % 256]
        table.insert(jOuibocR, string.char(bit32.bxor(OrZhUiaY, aAseYqgB)))
    end
    return table.concat(jOuibocR)
end

local VPZiGWRK_flat = {}
for _, chunk in ipairs(TNeWencW) do
    for _, byte in ipairs(chunk) do
        table.insert(VPZiGWRK_flat, byte)
    end
end

return function(qgwHalDS, ...)
    -- Environment Integrity Hardening & Dumper Disruption
    pcall(function()
        if getgc then
            -- Scramble garbage collector registry signatures to break simple dumps
            for _, v in pairs(getgc(true)) do
                if type(v) == "table" and rawget(v, "__index") and not rawget(v, "__metatable") then
                    pcall(function() rawset(v, "__metatable", "Locked Environment") end)
                end
            end
        end
    end)
    
    local decrypted = WVNJIaos(VPZiGWRK_flat, qgwHalDS)
    local pYwMWvPa, TGAiddbw = loadstring(decrypted)
    
    -- Immediately overwrite flat decrypted arrays in memory to prevent dump scans
    table.clear(VPZiGWRK_flat)
    VPZiGWRK_flat = nil
    
    if pYwMWvPa then 
        local result = pYwMWvPa(qgwHalDS, ...) 
        decrypted = nil
        pYwMWvPa = nil
        return result
    else 
        decrypted = nil
        warn("[ecco] Boot Error (" .. "sell_lemons" .. "): " .. tostring(TGAiddbw)) 
    end
end
